// Filtra apenas conversas com alerta
const conversations = $input.all().map(i => i.json);

const alertsToSave = conversations.filter(c => c.alert_level !== 'ok');

if (alertsToSave.length === 0) {
  return [{ json: { alerts: [], count: 0 } }];
}

return alertsToSave.map(c => ({ json: c }));
